import React, { useMemo, useState, useEffect, Suspense } from 'react';
import {
    Dialog,
    DialogTitle,
    DialogContent,
    Box,
    TextField,
    Button,
    Stack,
    Typography,
    IconButton,
    CircularProgress
} from '@mui/material';

import CloseIcon from '@mui/icons-material/Close';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';

const MapView = React.lazy(() => import('modules/attendance/components/MapView'));

const EmployeeRouteModal = ({ open, onClose, employee, role = 'EMPLOYEE' }) => {

    const [filters, setFilters] = useState({
        from: '',
        to: ''
    });

    const [filteredPunches, setFilteredPunches] = useState([]);

    const getToday = () => new Date().toISOString().split('T')[0];

    // ================= INIT =================
    useEffect(() => {
        if (!employee) return;

        const today = getToday();

        setFilters({
            from: today,
            to: today
        });

    }, [employee, role]);

    // ================= FILTER =================
    const applyFilter = () => {

        if (!employee?.records) return;

        let records = [...employee.records];

        // 🔥 EMPLOYEE: ONLY TODAY
        if (role !== 'ADMIN') {
            const today = getToday();

            records = records.filter(r =>
                new Date(r.punched_at).toISOString().split('T')[0] === today
            );

            setFilteredPunches(records);
            return;
        }

        // 🔥 ADMIN FILTER
        if (filters.from) {
            records = records.filter(r =>
                new Date(r.punched_at) >= new Date(filters.from)
            );
        }

        if (filters.to) {
            records = records.filter(r =>
                new Date(r.punched_at) <= new Date(filters.to + "T23:59:59")
            );
        }

        setFilteredPunches(records);
    };

    useEffect(() => {
        applyFilter();
    }, [filters, employee, role]);

    return (
        <Dialog
            open={open}
            onClose={onClose}
            fullScreen
        >

            {/* ================= HEADER ================= */}
            <DialogTitle
                sx={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center'
                }}
            >
                {/* LEFT */}
                <Box display="flex" alignItems="center" gap={1}>
                    <IconButton onClick={onClose}>
                        <ArrowBackIcon />
                    </IconButton>

                    <Typography fontWeight="bold">
                        {employee?.name} - Route Tracking
                    </Typography>
                </Box>

                {/* RIGHT */}
                <IconButton onClick={onClose}>
                    <CloseIcon />
                </IconButton>
            </DialogTitle>

            {/* ================= BODY ================= */}
            <DialogContent>

                {/* ADMIN FILTER */}
                {role === 'ADMIN' && (
                    <Stack direction="row" spacing={2} mb={2} flexWrap="wrap">

                        <TextField
                            type="date"
                            label="From"
                            size="small"
                            value={filters.from}
                            InputLabelProps={{ shrink: true }}
                            onChange={(e) =>
                                setFilters(prev => ({
                                    ...prev,
                                    from: e.target.value
                                }))
                            }
                        />

                        <TextField
                            type="date"
                            label="To"
                            size="small"
                            value={filters.to}
                            InputLabelProps={{ shrink: true }}
                            onChange={(e) =>
                                setFilters(prev => ({
                                    ...prev,
                                    to: e.target.value
                                }))
                            }
                        />

                        <Button variant="contained" onClick={applyFilter}>
                            Apply
                        </Button>

                        <Button
                            variant="outlined"
                            onClick={() => {
                                const today = getToday();
                                setFilters({ from: today, to: today });
                            }}
                        >
                            Today
                        </Button>

                    </Stack>
                )}

                {/* INFO */}
                <Typography variant="body2" sx={{ mb: 1 }}>
                    Showing {filteredPunches.length} points
                    {role !== 'ADMIN' && " (Today only)"}
                </Typography>

                {/* ================= MAP ================= */}
                <Suspense
                    fallback={
                        <Box textAlign="center" mt={5}>
                            <CircularProgress />
                        </Box>
                    }
                >
                    <MapView punches={filteredPunches} />
                </Suspense>

            </DialogContent>

        </Dialog>
    );
};

export default EmployeeRouteModal;